const APP = {
  name: "RTP Indonesia Web Worker",
  brand: "Republik Trader Perintis",
  version: "1.6.0",
  codename: "Member Access Gateway",
  timezone: "Asia/Jakarta",
  buildDate: "2026-06-28",
  owner: "RTP Indonesia"
};

const STARTED_AT = Date.now();

function pad2(n) {
  return String(n).padStart(2, "0");
}

function nowParts() {
  const now = new Date();
  const wib = new Date(now.toLocaleString("en-US", { timeZone: APP.timezone }));
  const dayNames = ["Minggu", "Senin", "Selasa", "Rabu", "Kamis", "Jumat", "Sabtu"];
  return {
    utcISO: now.toISOString(),
    wibISO: `${wib.getFullYear()}-${pad2(wib.getMonth() + 1)}-${pad2(wib.getDate())}T${pad2(wib.getHours())}:${pad2(wib.getMinutes())}:${pad2(wib.getSeconds())}+07:00`,
    wibDate: `${pad2(wib.getDate())}-${pad2(wib.getMonth() + 1)}-${wib.getFullYear()}`,
    wibTime: `${pad2(wib.getHours())}:${pad2(wib.getMinutes())}:${pad2(wib.getSeconds())}`,
    wibHour: wib.getHours(),
    wibDay: dayNames[wib.getDay()],
    timestamp: now.getTime()
  };
}

function jsonResponse(data, status = 200) {
  return new Response(JSON.stringify(data, null, 2), {
    status,
    headers: {
      ...securityHeaders("application/json; charset=UTF-8"),
      "cache-control": "no-store",
      "access-control-allow-origin": "*",
      "access-control-allow-methods": "GET, HEAD, POST, OPTIONS",
      "access-control-allow-headers": "Content-Type"
    }
  });
}

function apiMeta(path) {
  const t = nowParts();
  return {
    app: APP.name,
    brand: APP.brand,
    version: APP.version,
    codename: APP.codename,
    path,
    timezone: APP.timezone,
    generatedAtUTC: t.utcISO,
    generatedAtWIB: t.wibISO
  };
}


function normalizeActivityType(type) {
  const value = String(type || "SYSTEM").toUpperCase().trim();
  const allowed = ["BUY", "SELL", "LAYER", "TP", "SL", "MANUAL", "SYSTEM", "AI", "NEWS", "COPYTRADE", "LIVE"];
  return allowed.includes(value) ? value : "SYSTEM";
}

function activityTone(type) {
  const t = normalizeActivityType(type);
  if (["BUY", "TP", "COPYTRADE", "LIVE"].includes(t)) return "";
  if (["SELL", "SL"].includes(t)) return "loss";
  if (["SYSTEM", "AI", "NEWS", "MANUAL", "LAYER"].includes(t)) return "update";
  return "update";
}

function makeActivity({ id, offsetMinutes = 0, type = "SYSTEM", symbol = "RTP", title, detail, status = "UPDATE", lot = null, profit = null }, baseTime) {
  const d = new Date(baseTime.timestamp - offsetMinutes * 60 * 1000);
  const wib = new Date(d.toLocaleString("en-US", { timeZone: APP.timezone }));
  const activityType = normalizeActivityType(type);
  return {
    id,
    type: activityType,
    symbol,
    lot,
    profit,
    title: title || activityType,
    detail: detail || symbol,
    status,
    tone: activityTone(activityType),
    timeWIB: `${pad2(wib.getHours())}:${pad2(wib.getMinutes())}`,
    timestampUTC: d.toISOString(),
    timestampWIB: `${wib.getFullYear()}-${pad2(wib.getMonth() + 1)}-${pad2(wib.getDate())}T${pad2(wib.getHours())}:${pad2(wib.getMinutes())}:${pad2(wib.getSeconds())}+07:00`,
    source: "placeholder-engine"
  };
}

